const jobInfo = $('Loop All Jobs').item.json;

const dbResult = items.map(i => i.json);

let status = "MISSING";
let details = "Job did not run (No data found for this date).";
let isError = true;

if (dbResult.length > 0 && dbResult[0].task_name) {
  const row = dbResult[0];

  if (row.status === 'SUCCESS') {
    status = "SUCCESS";
    details = "Job completed successfully.";
    isError = false;
  } 
  else {
    status = "FAILED";
    const tracebackSnippet = row.traceback ? row.traceback.substring(0, 200) + '...' : 'No traceback available';

    details = `⚠️ *Status:* ${row.status}\n` +
              `📄 *Result:* ${row.result || 'NULL'}\n` +
              `🐞 *Traceback:* ${tracebackSnippet}\n` +
              `🔧 *Args:* ${row.task_args}\n` +
              `⚙️ *Kwargs:* ${row.task_kwargs}`;
    isError = true;
  }
} 

return [{
  json: {
    jobName: jobInfo.friendlyName,
    taskName: jobInfo.taskName,
    status: status,
    details: details,
    isError: isError
  }
}];

const results = items.map(item => item.json);
let errors = results.filter(job => job.isError);
let successes = results.filter(job => !job.isError);
let checkDate = $('Calculate Yesterday').first().json.check_date;
let message = "";
let outputItems = [];


if (errors.length > 0) {

    message = `🚨 *CRITICAL ETL REPORT* 🚨\n*Date:* ${checkDate}\n\n`;

    message += `*--- ❌ FAILURES (${errors.length}) ---*\n`;
    errors.forEach(err => {

        if (err.status === 'MISSING') {
            message += `• *MISSING:* ${err.jobName}\n> Job data not found for ${checkDate}.\n`;
        } else {
            message += `• *FAILED:* ${err.jobName} [Status: ${err.status}]\n>${err.details.replace(/\n/g, '\n> ')}\n`;
        }
        message += `\n`;
    });

    outputItems.push({
        json: {
            text: message,
            hasErrors: true
        }
    });

}

return outputItems;

